import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { BehaviorSubject, Observable, tap } from 'rxjs';
import { environment } from '../../environments/environment';
import { User } from '../models/user.model';

interface AuthResponse {
  token: string;
  tokenType: string;
}

interface MessageResponse {
  message: string;
}

interface LoginPayload {
  email: string;
  password: string;
}

interface RegisterPayload {
  name: string;
  email: string;
  password: string;
}

interface ProfileUpdatePayload {
  name: string;
  avatarUrl?: string;
}

interface UserProfileResponse {
  id: number;
  name: string;
  email: string;
  avatarUrl?: string | null;
}

interface StoredProfile {
  name: string;
  email: string;
  avatarUrl?: string;
}

@Injectable({
  providedIn: 'root'
})
export class AuthService {
  private tokenKey = 'corpnet_token';
  private userKey = 'corpnet_user';
  private profileKey = 'corpnet_profile';
  private currentUserSubject = new BehaviorSubject<User | null>(this.getStoredUser());
  currentUser$ = this.currentUserSubject.asObservable();

  constructor(private http: HttpClient) {}

  login(payload: LoginPayload): Observable<AuthResponse> {
    return this.http
      .post<AuthResponse>(`${environment.apiUrl}/auth/login`, payload)
      .pipe(tap((response) => this.setSession(response, payload.email)));
  }

  register(payload: RegisterPayload): Observable<MessageResponse> {
    return this.http
      .post<MessageResponse>(`${environment.apiUrl}/auth/register`, payload)
      .pipe(tap(() => this.storeProfile(payload)));
  }

  verifyEmail(token: string): Observable<MessageResponse> {
    return this.http.get<MessageResponse>(`${environment.apiUrl}/auth/verify`, {
      params: { token }
    });
  }

  updateProfile(payload: ProfileUpdatePayload): Observable<UserProfileResponse> {
    return this.http
      .put<UserProfileResponse>(`${environment.apiUrl}/users/me`, payload)
      .pipe(
        tap((response) => {
          const currentUser = this.currentUserSubject.value;
          const resolvedAvatar =
            response.avatarUrl ?? payload.avatarUrl ?? currentUser?.avatarUrl;
          const user: User = {
            id: String(response.id),
            name: response.name,
            email: response.email,
            avatarUrl: resolvedAvatar ?? undefined
          };
          localStorage.setItem(this.userKey, JSON.stringify(user));
          this.storeProfile({ name: response.name, email: response.email, password: '' }, user.avatarUrl);
          this.currentUserSubject.next(user);
        })
      );
  }

  logout(): void {
    localStorage.removeItem(this.tokenKey);
    localStorage.removeItem(this.userKey);
    this.currentUserSubject.next(null);
  }

  isLoggedIn(): boolean {
    return !!this.getToken();
  }

  getToken(): string | null {
    return localStorage.getItem(this.tokenKey);
  }

  getCurrentUser(): User | null {
    return this.currentUserSubject.value;
  }

  private setSession(response: AuthResponse, email: string): void {
    localStorage.setItem(this.tokenKey, response.token);
    const user = this.buildUser(email);
    localStorage.setItem(this.userKey, JSON.stringify(user));
    this.currentUserSubject.next(user);
  }

  private buildUser(email: string): User {
    const storedProfile = this.getStoredProfile();
    const nameFromProfile = storedProfile && storedProfile.email === email ? storedProfile.name : null;
    const avatarFromProfile = storedProfile && storedProfile.email === email ? storedProfile.avatarUrl : undefined;
    const fallbackName = email.split('@')[0] || email;

    return {
      id: email,
      name: nameFromProfile ?? fallbackName,
      email,
      avatarUrl: avatarFromProfile
    };
  }

  private storeProfile(payload: RegisterPayload, avatarUrl?: string): void {
    const profile: StoredProfile = {
      name: payload.name,
      email: payload.email,
      avatarUrl
    };
    localStorage.setItem(this.profileKey, JSON.stringify(profile));
  }

  private getStoredProfile(): StoredProfile | null {
    const stored = localStorage.getItem(this.profileKey);
    if (!stored) {
      return null;
    }
    try {
      return JSON.parse(stored) as StoredProfile;
    } catch {
      return null;
    }
  }

  private getStoredUser(): User | null {
    const stored = localStorage.getItem(this.userKey);
    if (!stored) {
      return null;
    }
    try {
      return JSON.parse(stored) as User;
    } catch {
      return null;
    }
  }
}
