import { Component } from '@angular/core';
import { FormBuilder, Validators } from '@angular/forms';
import { MatSnackBar } from '@angular/material/snack-bar';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-verify-email',
  templateUrl: './verify-email.component.html',
  styleUrls: ['./verify-email.component.scss']
})
export class VerifyEmailComponent {
  loading = false;
  form = this.fb.nonNullable.group({
    token: ['', [Validators.required, Validators.minLength(6)]]
  });

  constructor(
    private fb: FormBuilder,
    private authService: AuthService,
    private snackBar: MatSnackBar
  ) {}

  submit(): void {
    if (this.form.invalid) {
      return;
    }

    this.loading = true;
    this.authService.verifyEmail(this.form.getRawValue().token).subscribe({
      next: (response) => {
        this.loading = false;
        this.snackBar.open(response.message ?? 'Email verified. You can now log in.', 'Close', {
          duration: 3000
        });
      },
      error: () => {
        this.loading = false;
        this.snackBar.open('Verification failed. Check the token.', 'Close', { duration: 3000 });
      }
    });
  }
}
